 90→    if merkle_tree_config.height as u64 != ADDRESS_MERKLE_TREE_HEIGHT {
 91→        msg!(
 92→            "Unsupported Merkle tree height: {}. The only currently supported height is: {}",
 93→            merkle_tree_config.height,
 94→            ADDRESS_MERKLE_TREE_HEIGHT
 95→        );
 96→        return err!(AccountCompressionErrorCode::UnsupportedHeight);
 97→    }
 98→    if merkle_tree_config.canopy_depth != ADDRESS_MERKLE_TREE_CANOPY_DEPTH {
 99→        msg!(
100→            "Unsupported canopy depth: {}. The only currently supported depth is: {}",
101→            merkle_tree_config.canopy_depth,
102→            ADDRESS_MERKLE_TREE_CANOPY_DEPTH
103→        );
104→        return err!(AccountCompressionErrorCode::UnsupportedCanopyDepth);
105→    }
106→    if merkle_tree_config.close_threshold.is_some() {
107→        msg!("close_threshold is not supported yet");
108→        return err!(AccountCompressionErrorCode::UnsupportedCloseThreshold);
109→    }
110→    let minimum_sequence_threshold = merkle_tree_config.roots_size + SAFETY_MARGIN;
111→    if queue_config.sequence_threshold < minimum_sequence_threshold {
112→        msg!(
113→            "Invalid sequence threshold: {}. Should be at least {}",
114→            queue_config.sequence_threshold,
115→            minimum_sequence_threshold
116→        );
117→        return err!(AccountCompressionErrorCode::InvalidSequenceThreshold);
118→    }
119→    let owner = match ctx.accounts.registered_program_pda.as_ref() {
120→        Some(registered_program_pda) => {
121→            check_signer_is_registered_or_authority::<
122→                InitializeAddressMerkleTreeAndQueue,
123→                RegisteredProgram,
124→            >(&ctx, registered_program_pda)?;
125→            registered_program_pda.group_authority_pda
126→        }
127→        None => ctx.accounts.authority.key(),
128→    };
129→    let merkle_tree_expected_size = AddressMerkleTreeAccount::size(
130→        merkle_tree_config.height as usize,
131→        merkle_tree_config.changelog_size as usize,
132→        merkle_tree_config.roots_size as usize,
133→        merkle_tree_config.canopy_depth as usize,
134→        merkle_tree_config.address_changelog_size as usize,
135→    );
136→    let queue_expected_size = QueueAccount::size(queue_config.capacity as usize)?;
137→    let merkle_tree_rent = check_account_balance_is_rent_exempt(
138→        &ctx.accounts.merkle_tree.to_account_info(),
139→        merkle_tree_expected_size,
140→    )
141→    .map_err(ProgramError::from)?;
142→    check_account_balance_is_rent_exempt(
143→        &ctx.accounts.queue.to_account_info(),
144→        queue_expected_size,
145→    )
146→    .map_err(ProgramError::from)?;
147→    process_initialize_address_queue(
148→        &ctx.accounts.queue.to_account_info(),
149→        &ctx.accounts.queue,
150→        index,
151→        owner,
152→        program_owner,
153→        forester,
154→        ctx.accounts.merkle_tree.key(),
155→        queue_config.capacity,
156→        queue_config.sequence_threshold,
157→        queue_config.network_fee.unwrap_or_default(),
158→        merkle_tree_config.rollover_threshold,
159→        merkle_tree_config.close_threshold,
