 1→use crate::{context::AcpAccount, errors::AccountCompressionErrorCode};
 2→
 3→pub fn get_queue_and_tree_accounts<'a, 'b, 'info>(
 4→    accounts: &'b mut [AcpAccount<'a, 'info>],
 5→    queue_index: usize,
 6→    tree_index: usize,
 7→) -> std::result::Result<
 8→    (&'b mut AcpAccount<'a, 'info>, &'b mut AcpAccount<'a, 'info>),
 9→    AccountCompressionErrorCode,
10→> {
11→    let (smaller, bigger) = if queue_index < tree_index {
12→        (queue_index, tree_index)
13→    } else {
14→        (tree_index, queue_index)
15→    };
16→    let (left, right) = accounts.split_at_mut(bigger);
17→    let smaller_ref = &mut left[smaller];
18→    let bigger_ref = &mut right[0];
19→    Ok(if queue_index < tree_index {
20→        (smaller_ref, bigger_ref)
21→    } else {
22→        (bigger_ref, smaller_ref)
23→    })
24→}
