 1→use anchor_lang::prelude::*;
 2→use light_compressed_account::instruction_data::insert_into_queues::InsertIntoQueuesInstructionData;
 3→use light_zero_copy::traits::ZeroCopyAt;
 4→
 5→use super::{
 6→    insert_addresses::insert_addresses, insert_leaves::insert_leaves,
 7→    insert_nullifiers::insert_nullifiers,
 8→};
 9→use crate::{context::AcpAccount, errors::AccountCompressionErrorCode, GenericInstruction};
10→
11→pub fn process_insert_into_queues<'a, 'b, 'c: 'info, 'info>(
12→    ctx: &Context<'a, 'b, 'c, 'info, GenericInstruction<'info>>,
13→    bytes: Vec<u8>,
14→) -> Result<()> {
15→    let (inputs, _) = InsertIntoQueuesInstructionData::zero_copy_at(bytes.as_slice())
16→        .map_err(ProgramError::from)?;
17→    if inputs.addresses.len() > 8 {
18→        msg!(
19→            "Too many addresses: {}. The maximum is 8.",
20→            inputs.addresses.len()
21→        );
22→        return Err(AccountCompressionErrorCode::TooManyAddresses.into());
23→    }
24→    if inputs.nullifiers.len() > 10 {
25→        msg!(
26→            "Too many nullifiers: {}. The maximum is 10.",
27→            inputs.nullifiers.len()
28→        );
29→        return Err(AccountCompressionErrorCode::TooManyNullifiers.into());
30→    }
31→    let authority = ctx.accounts.authority.to_account_info();
32→    // Checks accounts for every account in remaining accounts:
33→    // 1. program ownership
34→    // 2. discriminator
35→    // 3. signer eligibility
36→    let mut accounts = AcpAccount::from_account_infos(
37→        ctx.remaining_accounts,
38→        &authority,
39→        inputs.is_invoked_by_program(),
40→        inputs.bump,
41→    )?;
42→    if inputs.nullifiers.is_empty() && inputs.addresses.is_empty() && inputs.leaves.is_empty() {
43→        return Err(AccountCompressionErrorCode::InputElementsEmpty.into());
44→    }
45→
46→    let current_slot = Clock::get()?.slot;
47→    // msg!("insert_nullifiers {:?}", inputs.nullifiers.len());
48→    // msg!("insert_leaves {:?}", inputs.leaves.len());
49→    // msg!("insert_addresses {:?}", inputs.addresses.len());
50→
51→    #[cfg(feature = "bench-sbf")]
52→    light_heap::bench_sbf_start!("append_leaves");
53→    insert_leaves(
54→        inputs.leaves.as_slice(),
55→        inputs.start_output_appends,
56→        inputs.num_output_queues,
57→        &mut accounts,
58→        &current_slot,
59→    )?;
60→    #[cfg(feature = "bench-sbf")]
61→    light_heap::bench_sbf_end!("append_leaves");
62→
63→    #[cfg(feature = "bench-sbf")]
64→    light_heap::bench_sbf_start!("insert_nullifiers");
65→    insert_nullifiers(
66→        inputs.num_queues,
67→        inputs.tx_hash,
68→        inputs.nullifiers.as_slice(),
69→        &mut accounts,
70→        &current_slot,
71→    )?;
72→    #[cfg(feature = "bench-sbf")]
73→    light_heap::bench_sbf_end!("insert_nullifiers");
74→
75→    #[cfg(feature = "bench-sbf")]
76→    light_heap::bench_sbf_start!("insert_addresses");
77→    insert_addresses(
78→        inputs.num_address_queues,
79→        inputs.addresses.as_slice(),
80→        &mut accounts,
81→        &current_slot,
82→    )?;
83→
84→    #[cfg(feature = "bench-sbf")]
85→    light_heap::bench_sbf_end!("insert_addresses");
86→    Ok(())
87→}
