    #[account(mut)]
    pub nullifier_queue: AccountLoader<'info, QueueAccount>,
}

impl GroupAccess for StateMerkleTreeAccount {
    fn get_owner(&self) -> Pubkey {
        self.metadata.access_metadata.owner.into()
