 68→    #[inline(always)]
 69→    fn set_additive_fee(&mut self, fee: u64, index: u8) -> Result<()> {
 70→        let payment = self.rollover_fee_payments.iter_mut().find(|a| a.0 == index);
 71→        match payment {
 72→            Some(payment) => {
 73→                payment.1 = payment
 74→                    .1
 75→                    .checked_add(fee)
 76→                    .ok_or(ProgramError::ArithmeticOverflow)?;
 77→            }
 78→            None => self.rollover_fee_payments.push((index, fee)),
 79→        };
 80→        Ok(())
 81→    }
 82→
 83→    #[profile]
 84→    pub fn set_network_fee_v2(&mut self, fee: u64, index: u8) {
 85→        if !self.network_fee_is_set {
 86→            self.network_fee_is_set = true;
 87→            self.rollover_fee_payments.push((index, fee));
 88→        }
 89→    }
