 91→    pub fn get_or_hash_pubkey(&mut self, pubkey: Pubkey) -> [u8; 32] {
 92→        let hashed_pubkey = self
 93→            .hashed_pubkeys
 94→            .iter()
 95→            .find(|a| a.0 == pubkey)
 96→            .map(|a| a.1);
 97→        match hashed_pubkey {
 98→            Some(hashed_pubkey) => hashed_pubkey,
 99→            None => {
100→                let hashed_pubkey = hash_to_bn254_field_size_be(pubkey.as_ref());
101→                self.hashed_pubkeys.push((pubkey, hashed_pubkey));
102→                hashed_pubkey
103→            }
104→        }
105→    }
106→}
