108→impl<'info> SystemContext<'info> {
109→    #[track_caller]
110→    pub fn get_index_or_insert(
111→        &mut self,
112→        ix_data_index: u8,
113→        remaining_accounts: &'info [AccountInfo],
114→        name: &str,
115→    ) -> std::result::Result<u8, SystemProgramError> {
116→        let queue_index = self
117→            .account_indices
118→            .iter()
119→            .position(|a| *a == ix_data_index);
120→        match queue_index {
121→            Some(index) => Ok(index as u8),
122→            None => {
123→                self.account_indices.push(ix_data_index);
124→                let account_info =
125→                    &remaining_accounts
126→                        .get(ix_data_index as usize)
127→                        .ok_or_else(|| {
128→                            let location = Location::caller();
129→                            msg!(
130→                                "Index: {}, account name: {} {}:{}:{}",
131→                                ix_data_index,
132→                                name,
133→                                location.file(),
134→                                location.line(),
135→                                location.column()
136→                            );
137→                            SystemProgramError::PackedAccountIndexOutOfBounds
138→                        })?;
139→                self.accounts.push(AccountMeta {
140→                    pubkey: account_info.key(),
141→                    is_signer: false,
142→                    is_writable: true,
143→                });
144→                self.account_infos.push(account_info);
145→                Ok(self.account_indices.len() as u8 - 1)
146→            }
147→        }
148→    }
149→
150→    pub fn set_rollover_fee(&mut self, ix_data_index: u8, fee: u64) {
151→        let payment = self
152→            .rollover_fee_payments
153→            .iter_mut()
154→            .find(|a| a.0 == ix_data_index);
155→        match payment {
156→            Some(payment) => payment.1 += fee,
157→            None => self.rollover_fee_payments.push((ix_data_index, fee)),
158→        };
159→    }
160→
161→    /// Network fee distribution:
162→    /// - V1 state trees: charge per input (5000 lamports × num_inputs)
163→    /// - V2 batched state trees: charge once per tree if inputs > 0 OR outputs > 0 (5000 lamports)
164→    /// - Address creation: charge per address (10000 lamports × num_addresses)
165→    ///
166→    /// Examples (V1 state trees):
167→    /// 1. create account with 1 address, 0 inputs:     network fee 10,000 lamports
168→    /// 2. token transfer (1 input, 1 output):          network fee 5,000 lamports
169→    /// 3. transfer with 2 V1 inputs, 1 address:        network fee 20,000 lamports (2×5k + 1×10k)
170→    ///
171→    /// Examples (V2 batched state trees):
172→    /// 1. token transfer (1 input, 0 output):          network fee 5,000 lamports (once per tree)
173→    /// 2. token transfer (0 input, 1 output):          network fee 5,000 lamports (once per tree)
174→    /// 3. token transfer (1 input, 1 output):          network fee 5,000 lamports (once per tree)
175→    /// 4. transfer with 2 V2 inputs, 1 address:        network fee 15,000 lamports (5k + 1×10k)
176→    ///    Transfers rollover and network fees.
177→    pub fn transfer_fees(&self, accounts: &[AccountInfo], fee_payer: &AccountInfo) -> Result<()> {
178→        for (i, fee) in self.rollover_fee_payments.iter() {
179→            transfer_lamports_invoke(fee_payer, &accounts[*i as usize], *fee)?;
180→        }
181→        Ok(())
182→    }
183→}
