 15→#[profile]
 16→pub fn derive_new_addresses<'info, 'a, 'b: 'a, const ADDRESS_ASSIGNMENT: bool>(
 17→    new_address_params: impl Iterator<Item = &'a (dyn NewAddress<'b> + 'a)>,
 18→    remaining_accounts: &'info [AccountInfo],
 19→    context: &mut SystemContext<'info>,
 20→    cpi_ix_data: &mut InsertIntoQueuesInstructionDataMut<'_>,
 21→    accounts: &[AcpAccount<'info>],
 22→) -> Result<()> {
 23→    let invoking_program_id_clone = context.invoking_program_id;
 24→    let mut seq_index = 0;
 25→
 26→    for (i, new_address_params) in new_address_params.enumerate() {
 27→        let (address, rollover_fee) = match &accounts
 28→            .get(new_address_params.address_merkle_tree_account_index() as usize)
 29→            .ok_or(SystemProgramError::AddressAssignedAccountIndexOutOfBounds)?
 30→        {
 31→            AcpAccount::AddressTree((pubkey, _)) => {
 32→                cpi_ix_data.addresses[i].queue_index = context.get_index_or_insert(
 33→                    new_address_params.address_queue_index(),
 34→                    remaining_accounts,
 35→                    "V1 address queue",
 36→                )?;
 37→                cpi_ix_data.addresses[i].tree_index = context.get_index_or_insert(
 38→                    new_address_params.address_merkle_tree_account_index(),
 39→                    remaining_accounts,
 40→                    "V1 address tree",
 41→                )?;
 42→
 43→                let network_fee = context
 44→                    .get_legacy_merkle_context(
 45→                        new_address_params.address_merkle_tree_account_index(),
 46→                    )
 47→                    .ok_or(SystemProgramError::MissingLegacyMerkleContext)?
 48→                    .network_fee;
 49→                context.set_address_fee(network_fee, new_address_params.address_queue_index())?;
 50→
 51→                (
 52→                    derive_address_legacy(pubkey, &new_address_params.seed())
 53→                        .map_err(ProgramError::from)?,
 54→                    context
 55→                        .get_legacy_merkle_context(new_address_params.address_queue_index())
 56→                        .ok_or(SystemProgramError::MissingLegacyMerkleContext)?
 57→                        .rollover_fee,
 58→                )
 59→            }
 60→            AcpAccount::BatchedAddressTree(tree) => {
 61→                let invoking_program_id_bytes = if let Some(bytes) = new_address_params.owner() {
 62→                    Ok(bytes)
 63→                } else if let Some(invoking_program_id_clone) = invoking_program_id_clone.as_ref() {
 64→                    Ok(invoking_program_id_clone)
 65→                } else {
 66→                    Err(SystemProgramError::DeriveAddressError)
 67→                }?;
 68→
 69→                let tree_index = context.get_index_or_insert(
 70→                    new_address_params.address_merkle_tree_account_index(),
 71→                    remaining_accounts,
 72→                    "V2 address tree",
 73→                )?;
 74→                cpi_ix_data.addresses[i].tree_index = tree_index;
 75→                cpi_ix_data.addresses[i].queue_index = tree_index;
 76→
 77→                context.set_address_fee(
 78→                    tree.metadata.rollover_metadata.network_fee,
 79→                    new_address_params.address_merkle_tree_account_index(),
 80→                )?;
 81→
 82→                cpi_ix_data.insert_address_sequence_number(
 83→                    &mut seq_index,
 84→                    tree.pubkey(),
 85→                    tree.queue_batches.next_index,
 86→                );
 87→
 88→                // For batched address trees the queue is embedded in the tree
 89→                // account so both indices must point to the same account.
 90→                if new_address_params.address_queue_index()
 91→                    != new_address_params.address_merkle_tree_account_index()
 92→                {
 93→                    return Err(ProgramError::from(
 94→                        SystemProgramError::AddressMerkleTreeAccountDiscriminatorMismatch,
 95→                    ));
 96→                }
 97→
 98→                (
 99→                    derive_address(
100→                        &new_address_params.seed(),
101→                        &tree.pubkey().to_bytes(),
102→                        invoking_program_id_bytes,
103→                    ),
104→                    tree.metadata.rollover_metadata.rollover_fee,
105→                )
106→            }
107→            _ => {
108→                return Err(ProgramError::from(
109→                    SystemProgramError::AddressMerkleTreeAccountDiscriminatorMismatch,
110→                ))
111→            }
112→        };
113→        if !ADDRESS_ASSIGNMENT {
114→            // We are inserting addresses into two vectors to avoid unwrapping
115→            // the option in following functions.
116→            context.addresses.push(Some(address));
117→        } else if new_address_params
118→            .assigned_compressed_account_index()
119→            .is_some()
120→        {
121→            // Only addresses assigned to output accounts can be used in output accounts.
122→            context.addresses.push(Some(address));
123→        }
124→        cpi_ix_data.addresses[i].address = address;
125→
126→        context.set_rollover_fee(new_address_params.address_queue_index(), rollover_fee);
127→    }
128→    cpi_ix_data.num_address_queues = accounts
129→        .iter()
130→        .filter(|x| {
131→            matches!(
132→                x,
133→                AcpAccount::AddressTree(_) | AcpAccount::BatchedAddressTree(_)
134→            )
135→        })
136→        .count() as u8;
137→
138→    Ok(())
139→}
