156→    fn sum_check_test_with_num(
157→        input_amounts: &[u64],
158→        output_amounts: &[u64],
159→        relay_fee: Option<u64>,
160→        compress_or_decompress_lamports: Option<u64>,
161→        is_compress: bool,
162→        num_by_index: usize,
163→    ) -> Result<()> {
164→        let mut bytes = Vec::new();
165→
166→        let mut inputs = Vec::new();
167→        for (index, i) in input_amounts.iter().enumerate() {
168→            let prove_by_index = index < num_by_index;
169→            let merkle_context = PackedMerkleContext {
170→                merkle_tree_pubkey_index: 0,
171→                queue_pubkey_index: 0,
172→                leaf_index: 0,
