175→            inputs.push(PackedCompressedAccountWithMerkleContext {
176→                compressed_account: CompressedAccount {
177→                    owner: Pubkey::new_unique(),
178→                    lamports: *i,
179→                    address: None,
180→                    data: None,
181→                },
182→                merkle_context,
183→                root_index: 1,
184→                read_only: false,
185→            });
186→            inputs
187→                .last()
188→                .unwrap()
189→                .serialize(&mut bytes)
