201→                    data: None,
202→                },
203→                merkle_tree_index: 0,
204→            });
205→            outputs
206→                .last()
207→                .unwrap()
208→                .serialize(&mut output_bytes)
209→                .map_err(|_| ProgramError::InvalidArgument)?;
210→        }
211→
212→        let mut slice = bytes.as_slice();
213→        let mut inputs = Vec::new();
214→        for _ in 0..input_amounts.len() {
215→            let (input, _bytes) =
216→                ZPackedCompressedAccountWithMerkleContext::zero_copy_at(slice).unwrap();
217→            slice = _bytes;
