219→        }
220→        let mut slice = output_bytes.as_slice();
221→        let mut outputs = Vec::new();
222→        for _ in 0..output_amounts.len() {
223→            let (output, _bytes) =
224→                ZOutputCompressedAccountWithPackedContext::zero_copy_at(slice).unwrap();
225→            slice = _bytes;
