  1→use light_compressed_account::instruction_data::traits::InstructionData;
  2→use light_program_profiler::profile;
  3→use pinocchio::program_error::ProgramError;
  4→
  5→use crate::{context::WrappedInstructionData, errors::SystemProgramError, Result};
  6→
  7→#[profile]
  8→#[inline(always)]
  9→pub fn sum_check<'a, T: InstructionData<'a>>(
 10→    inputs: &WrappedInstructionData<'a, T>,
 11→    relay_fee: &Option<u64>,
 12→    is_compress: &bool,
 13→) -> Result<usize> {
 14→    let compress_or_decompress_lamports = &inputs.compress_or_decompress_lamports();
 15→    let input_compressed_accounts_with_merkle_context = inputs.input_accounts();
 16→
 17→    let output_compressed_accounts = inputs.output_accounts();
 18→    let mut sum: u64 = 0;
 19→    let mut num_prove_by_index_accounts = 0;
 20→    for compressed_account_with_context in input_compressed_accounts_with_merkle_context {
 21→        if compressed_account_with_context
 22→            .merkle_context()
 23→            .prove_by_index()
 24→        {
 25→            num_prove_by_index_accounts += 1;
 26→        }
 27→
 28→        sum = sum
 29→            .checked_add(compressed_account_with_context.lamports())
 30→            .ok_or(ProgramError::ArithmeticOverflow)
 31→            .map_err(|_| SystemProgramError::ComputeInputSumFailed)?;
 32→    }
 33→
 34→    if let Some(lamports) = compress_or_decompress_lamports {
 35→        if *is_compress {
 36→            sum = sum
 37→                .checked_add(*lamports)
 38→                .ok_or(ProgramError::ArithmeticOverflow)
 39→                .map_err(|_| SystemProgramError::ComputeOutputSumFailed)?;
 40→        } else {
 41→            sum = sum
 42→                .checked_sub(*lamports)
 43→                .ok_or(ProgramError::ArithmeticOverflow)
 44→                .map_err(|_| SystemProgramError::ComputeOutputSumFailed)?;
 45→        }
 46→    }
 47→
 48→    for compressed_account in output_compressed_accounts {
 49→        sum = sum
 50→            .checked_sub(compressed_account.lamports())
 51→            .ok_or(ProgramError::ArithmeticOverflow)
 52→            .map_err(|_| SystemProgramError::ComputeOutputSumFailed)?;
 53→    }
 54→
 55→    if let Some(relay_fee) = relay_fee {
 56→        sum = sum
 57→            .checked_sub(*relay_fee)
 58→            .ok_or(ProgramError::ArithmeticOverflow)
 59→            .map_err(|_| SystemProgramError::ComputeRpcSumFailed)?;
