 11→pub fn assert_compressed_mint_account(
 12→    compressed_mint_account: &light_client::indexer::CompressedAccount,
 13→    compressed_mint_address: [u8; 32],
 14→    spl_mint_pda: Pubkey,
 15→    decimals: u8,
 16→    mint_authority: Pubkey,
 17→    freeze_authority: Pubkey,
 18→    metadata: Option<TokenMetadataInstructionData>,
 19→) -> Mint {
 20→    // Derive mint_signer from spl_mint_pda by reversing the PDA derivation
 21→    // We need to find the mint_signer and bump used to create spl_mint_pda
 22→    // spl_mint_pda = PDA([COMPRESSED_MINT_SEED, mint_signer], program_id)
 23→    // Since we can't reverse this, we extract it from the actual compressed mint data
 24→    let compressed_account_data = compressed_mint_account.data.clone().unwrap();
 25→    let actual_compressed_mint: Mint =
 26→        BorshDeserialize::deserialize(&mut compressed_account_data.data.as_slice()).unwrap();
 27→    let mint_signer = actual_compressed_mint.metadata.mint_signer;
 28→    let bump = actual_compressed_mint.metadata.bump;
 29→
 30→    // Create expected extensions if metadata is provided
 31→    let expected_extensions = metadata.map(|meta| {
 32→        vec![ExtensionStruct::TokenMetadata(
 33→            light_token_interface::state::extensions::TokenMetadata {
 34→                update_authority: meta
 35→                    .update_authority
 36→                    .unwrap_or_else(|| Pubkey::from([0u8; 32]).into()),
 37→                mint: spl_mint_pda.into(),
 38→                name: meta.name,
 39→                symbol: meta.symbol,
 40→                uri: meta.uri,
 41→                additional_metadata: meta.additional_metadata.unwrap_or_default(),
 42→            },
 43→        )]
 44→    });
 45→
 46→    // Create expected compressed mint for comparison
 47→    let expected_compressed_mint = Mint {
 48→        base: BaseMint {
 49→            mint_authority: Some(mint_authority.into()),
 50→            supply: 0,
 51→            decimals,
 52→            is_initialized: true,
 53→            freeze_authority: Some(freeze_authority.into()),
 54→        },
 55→        metadata: MintMetadata {
 56→            version: 3,
 57→            mint: spl_mint_pda.into(),
 58→            mint_decompressed: false,
 59→            mint_signer,
 60→            bump,
 61→        },
 62→        reserved: [0u8; 16],
 63→        account_type: ACCOUNT_TYPE_MINT,
 64→        compression: light_compressible::compression_info::CompressionInfo::default(),
 65→        extensions: expected_extensions,
 66→    };
 67→
 68→    // Verify the account exists and has correct properties
 69→    assert_eq!(
 70→        compressed_mint_account.address.unwrap(),
 71→        compressed_mint_address
 72→    );
 73→    assert_eq!(compressed_mint_account.owner, light_compressed_token::ID);
 74→    assert_eq!(compressed_mint_account.lamports, 0);
 75→
 76→    // Verify the compressed mint data
 77→    let compressed_account_data = compressed_mint_account.data.clone().unwrap();
 78→    assert_eq!(
 79→        compressed_account_data.discriminator,
 80→        light_compressed_token::constants::COMPRESSED_MINT_DISCRIMINATOR
 81→    );
 82→
 83→    // Deserialize and verify the Mint struct matches expected
 84→    let compressed_mint: Mint =
 85→        BorshDeserialize::deserialize(&mut compressed_account_data.data.as_slice()).unwrap();
 86→    println!("Compressed Mint: {:?}", compressed_mint);
 87→    assert_eq!(compressed_mint, expected_compressed_mint);
 88→    if let Some(extensions) = compressed_mint.extensions {
 89→        println!("Compressed Mint extensions: {:?}", extensions);
 90→    }
 91→    assert_sha_account_hash(compressed_mint_account).unwrap();
 92→
 93→    expected_compressed_mint
 94→}
