142→// Test that each slot is active in exactly one epoch
143→fn test_protocol_config_active_phase_continuity_for_config(config: ProtocolConfig) {
144→    // Test for 10 epochs
145→    let epochs = 10;
146→
147→    let total_slots_to_test = config.active_phase_length * epochs;
148→
149→    for slot in config.genesis_slot..(config.genesis_slot + total_slots_to_test) {
150→        if slot < config.genesis_slot + config.registration_phase_length {
151→            // assert that is registration phase
152→            assert_eq!(config.get_latest_register_epoch(slot).unwrap(), 0);
153→            continue;
154→        }
155→        let mut active_epochs = HashSet::new();
156→        for offset in -1..1 {
157→            let epoch = config.get_current_epoch(slot) as i64 + offset;
158→            if epoch < 0 {
159→                continue;
160→            }
161→
162→            let phases = get_epoch_phases(&config, epoch as u64);
163→
164→            if slot >= phases.active.start && slot <= phases.active.end {
165→                active_epochs.insert(epoch);
166→            }
167→        }
168→
169→        assert_eq!(
170→            active_epochs.len(),
171→            1,
172→            "Slot {} should be active in exactly one epoch, but was active in {} epochs. Protocol config: {:?}",
173→            slot,
174→            active_epochs.len(),
175→            config
176→        );
177→    }
178→}
