  1→use light_compressed_account::{
  2→    hash_to_bn254_field_size_be,
  3→    instruction_data::{
  4→        insert_into_queues::{InsertIntoQueuesInstructionDataMut, MerkleTreeSequenceNumber},
  5→        traits::InstructionData,
  6→    },
  7→    TreeType,
  8→};
  9→use light_hasher::{Hasher, Poseidon};
 10→use light_program_profiler::profile;
 11→use pinocchio::{account_info::AccountInfo, msg, program_error::ProgramError};
 12→
 13→use crate::{
 14→    accounts::remaining_account_checks::AcpAccount,
 15→    context::{SystemContext, WrappedInstructionData},
 16→    errors::SystemProgramError,
 17→    Result,
 18→};
 19→
 20→/// Creates CPI accounts, instruction data, and performs checks.
 21→/// - Merkle tree indices must be in order.
 22→/// - Hashes output accounts for insertion and event.
 23→/// - Collects sequence numbers for event.
 24→///
 25→/// Checks:
 26→/// 1. Checks whether a Merkle tree is program owned, if so checks write
 27→///    eligibility.
 28→/// 2. Checks ordering of Merkle tree indices.
 29→/// 3. Checks that addresses in output compressed accounts have been created or
 30→///    exist in input compressed accounts. An address may not be used in an
 31→///    output compressed accounts. This will close the account.
 32→#[allow(clippy::too_many_arguments)]
 33→#[allow(clippy::type_complexity)]
 34→#[profile]
 35→pub fn create_outputs_cpi_data<'a, 'info, T: InstructionData<'a>>(
 36→    inputs: &WrappedInstructionData<'a, T>,
 37→    remaining_accounts: &'info [AccountInfo],
 38→    context: &mut SystemContext<'info>,
 39→    cpi_ix_data: &mut InsertIntoQueuesInstructionDataMut<'_>,
 40→    accounts: &[AcpAccount<'info>],
 41→) -> Result<[u8; 32]> {
 42→    if inputs.output_len() == 0 {
 43→        return Ok([0u8; 32]);
 44→    }
 45→    let mut current_index: i16 = -1;
 46→    let mut num_leaves_in_tree: u32 = 0;
 47→    let mut mt_next_index: u32 = 0;
 48→    let mut hashed_merkle_tree = [0u8; 32];
 49→    cpi_ix_data.start_output_appends = context.account_indices.len() as u8;
 50→    let mut index_merkle_tree_account_account = cpi_ix_data.start_output_appends;
 51→    let mut index_merkle_tree_account = 0;
 52→    let number_of_merkle_trees =
 53→        inputs.output_accounts().last().unwrap().merkle_tree_index() as usize + 1;
 54→
 55→    let mut merkle_tree_pubkeys =
 56→        Vec::<light_compressed_account::pubkey::Pubkey>::with_capacity(number_of_merkle_trees);
 57→    let mut hash_chain = [0u8; 32];
 58→    let mut rollover_fee = 0;
 59→    let mut is_batched = true;
 60→
 61→    for (j, account) in inputs.output_accounts().enumerate() {
 62→        // if mt index == current index Merkle tree account info has already been added.
 63→        // if mt index != current index, Merkle tree account info is new, add it.
 64→        #[allow(clippy::comparison_chain)]
 65→        if account.merkle_tree_index() as i16 == current_index {
 66→            // Do nothing, but it is the most common case.
 67→        } else if account.merkle_tree_index() as i16 > current_index {
 68→            current_index = account.merkle_tree_index().into();
 69→
 70→            let pubkey = match &accounts
 71→                .get(current_index as usize)
 72→                .ok_or(SystemProgramError::OutputMerkleTreeIndexOutOfBounds)?
 73→            {
 74→                AcpAccount::OutputQueue(output_queue) => {
 75→                    context.set_network_fee_v2(
 76→                        output_queue.metadata.rollover_metadata.network_fee,
 77→                        current_index as u8,
 78→                    );
 79→
 80→                    hashed_merkle_tree = output_queue.hashed_merkle_tree_pubkey;
 81→                    rollover_fee = output_queue.metadata.rollover_metadata.rollover_fee;
 82→                    mt_next_index = output_queue.batch_metadata.next_index as u32;
 83→                    cpi_ix_data.output_sequence_numbers[index_merkle_tree_account as usize] =
 84→                        MerkleTreeSequenceNumber {
 85→                            tree_pubkey: output_queue.metadata.associated_merkle_tree,
 86→                            queue_pubkey: *output_queue.pubkey(),
 87→                            tree_type: (TreeType::StateV2 as u64).into(),
 88→                            seq: output_queue.batch_metadata.next_index.into(),
 89→                        };
 90→                    is_batched = true;
 91→                    *output_queue.pubkey()
 92→                }
 93→                AcpAccount::StateTree((pubkey, tree)) => {
 94→                    cpi_ix_data.output_sequence_numbers[index_merkle_tree_account as usize] =
 95→                        MerkleTreeSequenceNumber {
 96→                            tree_pubkey: *pubkey,
 97→                            queue_pubkey: *pubkey,
 98→                            tree_type: (TreeType::StateV1 as u64).into(),
 99→                            seq: (tree.sequence_number() as u64 + 1).into(),
100→                        };
101→                    let merkle_context = context
102→                        .get_legacy_merkle_context(current_index as u8)
103→                        .ok_or(SystemProgramError::MissingLegacyMerkleContext)?;
104→                    hashed_merkle_tree = merkle_context.hashed_pubkey;
105→                    rollover_fee = merkle_context.rollover_fee;
106→                    mt_next_index = tree.next_index() as u32;
107→                    is_batched = false;
108→                    *pubkey
109→                }
110→                AcpAccount::Unknown() => {
111→                    msg!(
112→                        format!("found batched unknown create outputs {} ", current_index).as_str()
113→                    );
114→
115→                    return Err(
116→                        SystemProgramError::StateMerkleTreeAccountDiscriminatorMismatch.into(),
117→                    );
118→                }
119→                AcpAccount::BatchedAddressTree(_) => {
120→                    msg!(format!(
121→                        "found batched address tree create outputs {} ",
122→                        current_index
123→                    )
124→                    .as_str());
125→
126→                    return Err(
127→                        SystemProgramError::StateMerkleTreeAccountDiscriminatorMismatch.into(),
128→                    );
129→                }
130→                AcpAccount::BatchedStateTree(_) => {
131→                    msg!(
132→                        format!("found batched state tree create outputs {} ", current_index)
133→                            .as_str()
134→                    );
135→
136→                    return Err(
137→                        SystemProgramError::StateMerkleTreeAccountDiscriminatorMismatch.into(),
138→                    );
139→                }
140→                _ => {
141→                    msg!(format!("create outputs {} ", current_index).as_str());
142→
143→                    return Err(
144→                        SystemProgramError::StateMerkleTreeAccountDiscriminatorMismatch.into(),
145→                    );
146→                }
147→            };
148→            // check Merkle tree uniqueness
149→            if merkle_tree_pubkeys.contains(&pubkey) {
150→                return Err(SystemProgramError::OutputMerkleTreeNotUnique.into());
151→            } else {
152→                merkle_tree_pubkeys.push(pubkey);
153→            }
154→
155→            context.get_index_or_insert(
156→                account.merkle_tree_index(),
157→                remaining_accounts,
158→                "Output queue for V2 state trees (Merkle tree for V1 state trees)",
159→            )?;
160→            num_leaves_in_tree = 0;
161→            index_merkle_tree_account += 1;
162→            index_merkle_tree_account_account += 1;
163→        } else {
164→            // Check 2.
165→            // Output Merkle tree indices must be in order since we use the
166→            // number of leaves in a Merkle tree to determine the correct leaf
167→            // index. Since the leaf index is part of the hash this is security
168→            // critical.
169→            return Err(SystemProgramError::OutputMerkleTreeIndicesNotInOrder.into());
170→        }
171→
172→        // Check 3.
173→        if let Some(address) = account.address() {
174→            if let Some(position) = context.addresses.iter().position(|&x| x == Some(address)) {
175→                context.addresses.remove(position);
176→            } else {
177→                msg!(format!("context.addresses: {:?}", context.addresses).as_str());
178→                return Err(SystemProgramError::InvalidAddress.into());
179→            }
180→        }
181→        cpi_ix_data.output_leaf_indices[j] = (mt_next_index + num_leaves_in_tree).into();
182→
183→        num_leaves_in_tree += 1;
184→        if account.has_data() && context.invoking_program_id.is_none() {
185→            msg!("Invoking program is not provided.");
186→            msg!("Only program owned compressed accounts can have data.");
187→            return Err(SystemProgramError::InvokingProgramNotProvided.into());
188→        }
189→        let hashed_owner = match context
190→            .hashed_pubkeys
191→            .iter()
192→            .find(|x| x.0 == account.owner().to_bytes())
193→        {
194→            Some(hashed_owner) => hashed_owner.1,
195→            None => {
196→                let hashed_owner = hash_to_bn254_field_size_be(&account.owner().to_bytes());
197→                context
198→                    .hashed_pubkeys
199→                    .push((account.owner().into(), hashed_owner));
200→                hashed_owner
201→            }
202→        };
203→        // Compute output compressed account hash.
204→        cpi_ix_data.leaves[j].leaf = account
205→            .hash_with_hashed_values(
206→                &hashed_owner,
207→                &hashed_merkle_tree,
208→                &cpi_ix_data.output_leaf_indices[j].into(),
209→                is_batched,
210→            )
211→            .map_err(ProgramError::from)?;
212→        cpi_ix_data.leaves[j].account_index = index_merkle_tree_account_account - 1;
213→
214→        if !cpi_ix_data.nullifiers.is_empty() {
215→            if j == 0 {
216→                hash_chain = cpi_ix_data.leaves[j].leaf;
217→            } else {
218→                hash_chain = Poseidon::hashv(&[&hash_chain, &cpi_ix_data.leaves[j].leaf])
219→                    .map_err(ProgramError::from)?;
220→            }
221→        }
222→        context.set_rollover_fee(current_index as u8, rollover_fee);
223→    }
224→
225→    cpi_ix_data.num_output_queues = index_merkle_tree_account as u8;
226→    Ok(hash_chain)
227→}
