229→// Check that new addresses are assigned correctly to the compressed output accounts specified by index
230→#[profile]
231→pub fn check_new_address_assignment<'a, 'info, T: InstructionData<'a>>(
232→    inputs: &WrappedInstructionData<'a, T>,
233→    cpi_ix_data: &InsertIntoQueuesInstructionDataMut<'_>,
234→) -> std::result::Result<(), SystemProgramError> {
235→    for (derived_addresses, new_addresses) in
236→        cpi_ix_data.addresses.iter().zip(inputs.new_addresses())
237→    {
238→        if let Some(assigned_account_index) = new_addresses.assigned_compressed_account_index() {
239→            let output_account = inputs
240→                .get_output_account(assigned_account_index)
241→                .ok_or(SystemProgramError::NewAddressAssignedIndexOutOfBounds)?;
242→
243→            if derived_addresses.address
244→                != output_account
245→                    .address()
246→                    .ok_or(SystemProgramError::AddressIsNone)?
247→            {
248→                msg!(format!(
249→                    "derived_addresses.address {:?} != account address {:?}",
250→                    derived_addresses.address,
251→                    output_account.address()
252→                )
253→                .as_str());
254→                msg!(format!(
255→                    "account owner {:?}",
256→                    solana_pubkey::Pubkey::new_from_array(output_account.owner().into())
257→                )
258→                .as_str());
259→                msg!(format!(
260→                    "account merkle_tree_index {:?}",
261→                    output_account.merkle_tree_index()
262→                )
263→                .as_str());
264→                return Err(SystemProgramError::AddressDoesNotMatch);
265→            }
266→        }
267→    }
268→    Ok(())
269→}
