 46→impl SystemContext<'_> {
 47→    #[profile]
 48→    pub fn get_legacy_merkle_context(&mut self, index: u8) -> Option<&MerkleTreeContext> {
 49→        self.legacy_merkle_context
 50→            .iter()
 51→            .find(|a| a.0 == index)
 52→            .map(|a| &a.1)
 53→    }
 54→    pub fn set_legacy_merkle_context(&mut self, index: u8, context: MerkleTreeContext) {
 55→        self.legacy_merkle_context.push((index, context));
 56→    }
 57→
 58→    #[profile]
 59→    pub fn set_address_fee(&mut self, fee: u64, index: u8) -> Result<()> {
 60→        self.set_additive_fee(fee, index)
 61→    }
 62→
 63→    #[profile]
 64→    pub fn set_network_fee_v1(&mut self, fee: u64, index: u8) -> Result<()> {
 65→        self.set_additive_fee(fee, index)
 66→    }
 67→
 68→    #[inline(always)]
 69→    fn set_additive_fee(&mut self, fee: u64, index: u8) -> Result<()> {
 70→        let payment = self.rollover_fee_payments.iter_mut().find(|a| a.0 == index);
 71→        match payment {
 72→            Some(payment) => {
 73→                payment.1 = payment
 74→                    .1
 75→                    .checked_add(fee)
 76→                    .ok_or(ProgramError::ArithmeticOverflow)?;
 77→            }
 78→            None => self.rollover_fee_payments.push((index, fee)),
 79→        };
 80→        Ok(())
 81→    }
 82→
 83→    #[profile]
 84→    pub fn set_network_fee_v2(&mut self, fee: u64, index: u8) {
 85→        if !self.network_fee_is_set {
 86→            self.network_fee_is_set = true;
 87→            self.rollover_fee_payments.push((index, fee));
 88→        }
 89→    }
 90→
 91→    pub fn get_or_hash_pubkey(&mut self, pubkey: Pubkey) -> [u8; 32] {
 92→        let hashed_pubkey = self
 93→            .hashed_pubkeys
 94→            .iter()
 95→            .find(|a| a.0 == pubkey)
 96→            .map(|a| a.1);
 97→        match hashed_pubkey {
 98→            Some(hashed_pubkey) => hashed_pubkey,
 99→            None => {
100→                let hashed_pubkey = hash_to_bn254_field_size_be(pubkey.as_ref());
101→                self.hashed_pubkeys.push((pubkey, hashed_pubkey));
102→                hashed_pubkey
103→            }
104→        }
105→    }
106→}
