 48→pub struct TransactionParams {
 49→    pub v1_input_compressed_accounts: u8,
 50→    pub v2_input_compressed_accounts: bool,
 51→    pub num_output_compressed_accounts: u8,
 52→    pub num_new_addresses: u8,
